// ─── HELPERS ────────────────────────────────────────────────────────────────
export function wcClass(w) {
  if (!w || w === 'Any') return 'wa';
  const l = w.toLowerCase();
  if (l.includes('rainbow') && !l.includes('sunny') && !l.includes('rain')) return 'wrb';
  if (l.includes('rainy') || l.includes('rain')) return 'wr';
  if (l.includes('sunny')) return 'ws';
  return 'wa';
}

export function fmtPrice(p) {
  if (p === null || p === undefined) return null;
  return p.toLocaleString('de-DE');
}

export function getImgSrc(name, cat) {
  const mapped = (IMG_MAP[cat] && IMG_MAP[cat][name]) || name;
  if (cat === 'insects') return `/assets/img/insects/${mapped}.avif`;
  if (cat === 'birds') return `/assets/img/birds/${mapped}.avif`;
  if (cat === 'fish') return `/assets/img/fish/${mapped}.avif`;
  if (cat === 'recipes' || cat === 'gourmet') return `/assets/img/recipes/${mapped}.avif`;
  if (cat === 'flowers') return '';
  if (cat === 'gardening') {
    const fn = (IMG_MAP.gardening && IMG_MAP.gardening[name]) || name.toLowerCase();
    return `/assets/img/Crops/${fn}.avif`;
  }
  if (cat === 'npcs') {
    const fn = (IMG_MAP.npcs && IMG_MAP.npcs[name]) || name.toLowerCase();
    return `/assets/img/npcs/${fn}.webp`;
  }
  if (cat === 'animals') return `/assets/img/animals/${name.toLowerCase()}.avif`;
  if (cat === 'achievements') {
    const fn = (IMG_MAP.achievements && IMG_MAP.achievements[name]) || name;
    return `/assets/img/achievements/${fn}.avif`;
  }
  if (cat === 'collectables') {
    const fn = (IMG_MAP.collectables && IMG_MAP.collectables[name]) || name;
    return `/assets/img/collectables/${fn}.avif`;
  }
  if (cat === 'ingredients') return `/assets/img/ingredients/${name}.avif`;
  return '';
}